import { PropsIconsNameCore } from '@semparar/design-system-app';

export interface ParameterPointsProgramValue {
  questions: Array<{
    question: string;
    answer: string;
  }>;
  order: number;
  icon: PropsIconsNameCore;
}

export interface ParameterPointsProgramResponse {
  dateCreated: string;
  status: number;
  category: string;
  PK: string;
  dateUpdated: string;
  value: string | ParameterPointsProgramValue;
}

export enum ParameterPointsProgramStatus {
  IDLE = 'idle',
  LOADING = 'loading',
  SUCCESS = 'success',
  ERROR = 'error',
}

export interface ParameterPointsProgramState {
  data?: ParameterPointsProgramResponse[];
  selectedCategory?: ParameterPointsProgramResponse;
  status: ParameterPointsProgramStatus;
  pointsQuantity: number;
}

export function extractPointsQuantityFromParameterization(
  data?: ParameterPointsProgramResponse[]
): number {
  if (!data) return 0;

  const pointsRescueItem = data.find((item) => item.category === 'pointsRescueSentence');

  if (pointsRescueItem?.value) {
    try {
      let parsedValue =
        typeof pointsRescueItem.value === 'string'
          ? JSON.parse(pointsRescueItem.value)
          : pointsRescueItem.value;

      if (typeof parsedValue === 'string') {
        parsedValue = JSON.parse(parsedValue);
      }

      if (parsedValue && parsedValue.pointsQuantity !== undefined) {
        const ptsQuantity = Number(parsedValue.pointsQuantity);
        if (!isNaN(ptsQuantity)) {
          return ptsQuantity;
        }
      }
    } catch {
      return 0;
    }
  }

  return 0;
}

